import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { uploadResume, analyzeResume } from '../services/resume';
import { 
  DocumentArrowUpIcon, 
  DocumentTextIcon, 
  XMarkIcon,
  ArrowPathIcon 
} from '@heroicons/react/24/outline';
import { useDropzone } from 'react-dropzone';

const Analyze = () => {
  const [step, setStep] = useState(1);
  const [file, setFile] = useState(null);
  const [resumeText, setResumeText] = useState('');
  const [jobDescription, setJobDescription] = useState('');
  const [loading, setLoading] = useState(false);
  const [fileName, setFileName] = useState('');
  const navigate = useNavigate();

  const onDrop = useCallback(async (acceptedFiles) => {
    const selectedFile = acceptedFiles[0];
    if (!selectedFile) return;

    setFile(selectedFile);
    setFileName(selectedFile.name);
    
    try {
      setLoading(true);
      const response = await uploadResume(selectedFile);
      setResumeText(response.resumeText);
      setStep(2);
    } catch (error) {
      console.error('Upload failed:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'application/pdf': ['.pdf'],
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx']
    },
    maxFiles: 1,
    maxSize: 5 * 1024 * 1024 // 5MB
  });

  const handleAnalyze = async () => {
    if (!resumeText || !jobDescription) {
      alert('Please provide both resume and job description');
      return;
    }

    try {
      setLoading(true);
      const result = await analyzeResume({
        resumeText,
        jobDescription,
        fileName
      });
      navigate(`/result/${result.analysisId}`);
    } catch (error) {
      console.error('Analysis failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const removeFile = () => {
    setFile(null);
    setResumeText('');
    setFileName('');
  };

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900">Analyze your Resume</h1>
        <p className="text-gray-600 mt-1">
          Upload your resume and paste the job description to get AI-powered insights.
        </p>
      </div>

      {/* Progress Steps */}
      <div className="mb-8">
        <div className="flex items-center">
          <div className={`flex items-center ${step >= 1 ? 'text-indigo-600' : 'text-gray-400'}`}>
            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 font-semibold
              ${step >= 1 ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-gray-300 text-gray-400'}`}>
              1
            </div>
            <span className="ml-3 font-medium">Upload Resume</span>
          </div>
          <div className={`flex-1 h-1 mx-4 rounded ${step >= 2 ? 'bg-indigo-600' : 'bg-gray-300'}`} />
          <div className={`flex items-center ${step >= 2 ? 'text-indigo-600' : 'text-gray-400'}`}>
            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 font-semibold
              ${step >= 2 ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-gray-300 text-gray-400'}`}>
              2
            </div>
            <span className="ml-3 font-medium">Job Description</span>
          </div>
        </div>
      </div>

      <div className="card">
        {/* Step 1: Upload Resume */}
        {step === 1 && (
          <div>
            {!file ? (
              <div
                {...getRootProps()}
                className={`border-2 border-dashed rounded-xl p-12 text-center cursor-pointer transition-colors
                  ${isDragActive ? 'border-indigo-600 bg-indigo-50' : 'border-gray-300 hover:border-indigo-400 hover:bg-gray-50'}`}
              >
                <input {...getInputProps()} />
                <DocumentArrowUpIcon className="h-16 w-16 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900 mb-2">
                  {isDragActive ? 'Drop your resume here' : 'Upload your resume'}
                </h3>
                <p className="text-sm text-gray-500 mb-2">
                  Drag & drop or click to select
                </p>
                <p className="text-xs text-gray-400">
                  Supported formats: PDF, DOCX (Max 5MB)
                </p>
              </div>
            ) : (
              <div className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
                <div className="flex items-center">
                  <div className="bg-indigo-100 p-3 rounded-lg mr-4">
                    <DocumentTextIcon className="h-8 w-8 text-indigo-600" />
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">{fileName}</p>
                    <p className="text-sm text-gray-500">
                      {loading ? 'Processing...' : 'Ready for analysis'}
                    </p>
                  </div>
                </div>
                <button
                  onClick={removeFile}
                  className="p-2 hover:bg-gray-200 rounded-full transition-colors"
                  disabled={loading}
                >
                  <XMarkIcon className="h-5 w-5 text-gray-500" />
                </button>
              </div>
            )}
          </div>
        )}

        {/* Step 2: Job Description */}
        {step === 2 && (
          <div>
            <h3 className="text-lg font-medium text-gray-900 mb-4">
              Paste Job Description
            </h3>
            <textarea
              rows="12"
              className="input-field font-mono text-sm"
              placeholder="Paste the complete job description here..."
              value={jobDescription}
              onChange={(e) => setJobDescription(e.target.value)}
            />
            
            <div className="mt-6 flex justify-end space-x-3">
              <button
                onClick={() => setStep(1)}
                className="btn-secondary"
                disabled={loading}
              >
                Back
              </button>
              <button
                onClick={handleAnalyze}
                disabled={loading || !jobDescription.trim()}
                className="btn-primary flex items-center"
              >
                {loading ? (
                  <>
                    <ArrowPathIcon className="h-5 w-5 animate-spin mr-2" />
                    Analyzing...
                  </>
                ) : (
                  'Analyze Now'
                )}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* File Preview (if available) */}
      {step === 2 && resumeText && (
        <div className="mt-6 card">
          <h3 className="text-lg font-medium text-gray-900 mb-3">Resume Preview</h3>
          <div className="bg-gray-50 p-4 rounded-lg max-h-60 overflow-y-auto">
            <p className="text-sm text-gray-700 whitespace-pre-wrap">
              {resumeText}
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default Analyze;
